import React, { useState, useRef, useEffect } from 'react';
import PropTypes from 'prop-types';
import { useTheme } from '../../contexts/ThemeContext';
import TextAnimation from '../common/TextAnimation';
import styles from './Experience.module.css';

/**
 * Experience component with animated timeline
 * @param {Object} props - Component props
 * @param {Array} props.experiences - Array of experience objects
 * @returns {JSX.Element} Rendered Experience component
 */
const Experience = ({ experiences, className, ...props }) => {
  const { theme } = useTheme();
  const [visibleItems, setVisibleItems] = useState({});
  const timelineRef = useRef(null);
  
  const containerClasses = [
    styles.experienceSection,
    styles[`experience-${theme}`],
    className
  ].filter(Boolean).join(' ');

  // Setup Intersection Observer for animation on scroll
  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '0px',
      threshold: 0.2,
    };

    const observerCallback = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const itemId = entry.target.getAttribute('data-id');
          setVisibleItems((prev) => ({ ...prev, [itemId]: true }));
        }
      });
    };

    const observer = new IntersectionObserver(observerCallback, observerOptions);
    
    // Observe all timeline items
    const timelineItems = timelineRef.current?.querySelectorAll(`.${styles.timelineItem}`);
    if (timelineItems) {
      timelineItems.forEach((item) => observer.observe(item));
    }

    return () => {
      if (timelineItems) {
        timelineItems.forEach((item) => observer.unobserve(item));
      }
    };
  }, [experiences]);

  // Format date range
  const formatDateRange = (startDate, endDate) => {
    return `${startDate}${endDate ? ` - ${endDate}` : ' - Present'}`;
  };

  return (
    <section 
      className={containerClasses} 
      id="experience"
      data-testid="experience-section"
      {...props}
    >
      <div className={styles.container}>
        <TextAnimation
          element="h2"
          text="Experience"
          className={styles.sectionTitle}
          animation="fadeInUp"
          delay={200}
        />
        
        <div className={styles.timeline} ref={timelineRef}>
          {experiences.map((experience, index) => (
            <div 
              key={index}
              className={`${styles.timelineItem} ${visibleItems[index] ? styles.visible : ''}`}
              data-id={index}
              data-testid={`timeline-item-${index}`}
            >
              <div className={styles.timelineContent}>
                <div className={styles.dateRange}>
                  {formatDateRange(experience.startDate, experience.endDate)}
                </div>
                
                <h3 className={styles.jobTitle}>
                  {experience.title}
                </h3>
                
                <div className={styles.companyInfo}>
                  <span className={styles.companyName}>{experience.company}</span>
                  {experience.location && (
                    <span className={styles.location}>{experience.location}</span>
                  )}
                </div>
                
                {experience.description && (
                  <p className={styles.description}>{experience.description}</p>
                )}
                
                {experience.responsibilities && experience.responsibilities.length > 0 && (
                  <ul className={styles.responsibilitiesList}>
                    {experience.responsibilities.map((responsibility, respIndex) => (
                      <li key={respIndex} className={styles.responsibilityItem}>
                        {responsibility}
                      </li>
                    ))}
                  </ul>
                )}
                
                {experience.technologies && experience.technologies.length > 0 && (
                  <div className={styles.technologies}>
                    {experience.technologies.map((tech, techIndex) => (
                      <span key={techIndex} className={styles.technologyTag}>
                        {tech}
                      </span>
                    ))}
                  </div>
                )}
              </div>
              
              <div className={styles.timelineMarker}>
                <div className={styles.timelineDot}></div>
              </div>
            </div>
          ))}
        </div>
        
        {experiences.length === 0 && (
          <p className={styles.noExperience}>No experience data available.</p>
        )}
      </div>
    </section>
  );
};

Experience.propTypes = {
  experiences: PropTypes.arrayOf(
    PropTypes.shape({
      title: PropTypes.string.isRequired,
      company: PropTypes.string.isRequired,
      location: PropTypes.string,
      startDate: PropTypes.string.isRequired,
      endDate: PropTypes.string,
      description: PropTypes.string,
      responsibilities: PropTypes.arrayOf(PropTypes.string),
      technologies: PropTypes.arrayOf(PropTypes.string)
    })
  ),
  className: PropTypes.string
};

Experience.defaultProps = {
  experiences: [
    {
      title: 'Senior Frontend Developer',
      company: 'Tech Company',
      location: 'San Francisco, CA',
      startDate: 'Jan 2022',
      endDate: '',
      description: 'Led the development of the company\'s flagship product.',
      responsibilities: [
        'Architected and implemented new features',
        'Mentored junior developers',
        'Optimized application performance'
      ],
      technologies: ['React', 'TypeScript', 'GraphQL', 'Tailwind CSS']
    },
    {
      title: 'Frontend Developer',
      company: 'Startup Inc.',
      location: 'New York, NY',
      startDate: 'Mar 2019',
      endDate: 'Dec 2021',
      description: 'Worked on building responsive web applications.',
      responsibilities: [
        'Developed UI components',
        'Integrated RESTful APIs',
        'Implemented automated testing'
      ],
      technologies: ['JavaScript', 'React', 'Redux', 'CSS Modules']
    },
    {
      title: 'Web Developer Intern',
      company: 'Digital Agency',
      location: 'Boston, MA',
      startDate: 'Jun 2018',
      endDate: 'Feb 2019',
      description: 'Assisted in the development of client websites.',
      responsibilities: [
        'Built responsive layouts',
        'Fixed bugs and issues',
        'Participated in code reviews'
      ],
      technologies: ['HTML', 'CSS', 'JavaScript', 'jQuery']
    }
  ]
};

export default Experience;
